// Re-state each run's set-equality ensures so z3 instantiates the
// `map_values(|p: CPacket| p@).to_set()` term for both post1 and post2
// against the same right-hand side.
assert(post1_packets@.map_values(|p: CPacket| p@).to_set() ==
    pre_packets@.map_values(|p: CPacket| p@).to_set()
        + self_@.un_acked_messages_for_dest(src@, dst@));
assert(post2_packets@.map_values(|p: CPacket| p@).to_set() ==
    pre_packets@.map_values(|p: CPacket| p@).to_set()
        + self_@.un_acked_messages_for_dest(src@, dst@));

// Transitivity through the shared RHS gives the determinism observation
// on the abstract view-set of the output packet sequence.
assert(post1_packets@.map_values(|p: CPacket| p@).to_set() ==
    post2_packets@.map_values(|p: CPacket| p@).to_set());
